parameters.jsCode:
let rawText = $json.output;

try {
  if (!rawText) throw new Error("El campo 'output' no existe");

  // Limpiamos y convertimos a JSON
  const cleanText = rawText.replace(/```json|```/g, "").trim();
  const parsedData = JSON.parse(cleanText);

  // Devolvemos un solo objeto, empacando los correos en la propiedad "correos"
  return {
    json: {
      correos: Array.isArray(parsedData) ? parsedData : [parsedData]
    }
  };

} catch (error) {
  return {
    json: {
      error: "No se pudo extraer un JSON válido",
      mensaje_error: error.message
    }
  };
}
